SELECT SovraccolliBarcode.[Box Number], SovraccolliBarcode.Article, Item.[Description 2], SovraccolliBarcode.Color, SovraccolliBarcode.Assortment, [Assortment Quantity].[Variable Code], ConversioneTaglie.TagliaEuropea, Val([Quantity]) AS qty, Item_1.No_, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPC_CODE, [NavisionEan-step0].[Cross-Reference No_] AS EAN_CODE, [Assortment Quantity].[Order Variable Code]
FROM (((Item AS Item_1 INNER JOIN ((SovraccolliBarcode INNER JOIN Item ON SovraccolliBarcode.Article = Item.No_) INNER JOIN [Assortment Quantity] ON (Item.[Assortment Variable Group] = [Assortment Quantity].[Variable Group]) AND (SovraccolliBarcode.Assortment = [Assortment Quantity].[Assortment Code])) ON (Item_1.[Variable Code 02] = [Assortment Quantity].[Variable Code]) AND (Item_1.[Variable Code 01] = SovraccolliBarcode.Color) AND (Item_1.[Model Item No_] = SovraccolliBarcode.Article)) LEFT JOIN [NavisionEan-step0-UPC] ON Item_1.No_ = [NavisionEan-step0-UPC].[Item No_]) LEFT JOIN [NavisionEan-step0] ON Item_1.No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN ConversioneTaglie ON [Assortment Quantity].[Variable Code] = ConversioneTaglie.TagliaAmericana
ORDER BY SovraccolliBarcode.Article, SovraccolliBarcode.Color, SovraccolliBarcode.Assortment, [Assortment Quantity].[Order Variable Code];

